enum logic[0:0] { IDLE, ACTIVE } state;
always @(posedge clk, negedge rst) begin
  if (!rst) state <= IDLE;
  else case (state)
    IDLE:   state <= ACTIVE;
    ACTIVE: state <= IDLE;
  endcase
end
